pub fn gf16_pow(base: GF16, exponent: GF16) GF16 {
    if (gf16_is_nan(base) or gf16_is_nan(exponent)) {
        return GF16_NAN;
    }
    if (gf16_is_zero(base) and gf16_is_zero(exponent)) {
        return gf16_encode_f32(1.0);
    }
    if (gf16_is_zero(base) and gf16_is_positive(exponent)) {
        return GF16_ZERO_POS;
    }
    if (gf16_is_zero(base) and gf16_is_negative(exponent)) {
        return GF16_INF_POS;
    }
    const base_val = gf16_decode_to_f32(base);
    if ((base_val == 1.0) and !gf16_is_inf(exponent)) {
        return gf16_encode_f32(1.0);
    }
    if (gf16_is_zero(exponent)) {
        if (gf16_is_zero(base)) {
            return GF16_NAN;
        }
        return gf16_encode_f32(1.0);
    }
    const exp_val = gf16_decode_to_f32(exponent);
    if (exp_val == 1.0) {
        return base;
    }
    const result = @pow(base_val, exp_val);
    return gf16_encode_f32(result);
}
pub fn gf16_sin(x: GF16) GF16 {
    if (gf16_is_nan(x)) {
        return GF16_NAN;
    }
    if (gf16_is_inf(x)) {
        return GF16_NAN;
    }
    const x_val = gf16_decode_to_f32(x);
    const x_sq = x_val * x_val;
    const x_cub = x_sq * x_val;
    const x_5 = x_cub * x_sq;
    const x_7 = x_5 * x_sq;
    const term1 = x_val;
    const term2 = -x_cub / 6.0;
    const term3 = x_5 / 120.0;
    const term4 = -x_7 / 5040.0;
    const result = ((term1 + term2) + term3) + term4;
    return gf16_encode_f32(result);
}
pub fn gf16_cos(x: GF16) GF16 {
    if (gf16_is_nan(x)) {
        return GF16_NAN;
    }
    if (gf16_is_inf(x)) {
        return GF16_NAN;
    }
    const x_val = gf16_decode_to_f32(x);
    const x_sq = x_val * x_val;
    const x_4 = x_sq * x_sq;
    const x_6 = x_4 * x_sq;
    const term0 = 1.0;
    const term1 = -x_sq / 2.0;
    const term2 = x_4 / 24.0;
    const term3 = -x_6 / 720.0;
    const result = ((term0 + term1) + term2) + term3;
    return gf16_encode_f32(result);
}
