test "gf16_add_positive_values" {
    const a = gf16_encode_f32(1.5);
    const b = gf16_encode_f32(2.5);
    const result = gf16_add(a, b);
    const decoded = gf16_decode_to_f32(result);
    try std.testing.expectApproxEqAbs(4.0, decoded, 0.1);
}
test "gf16_add_negative_values" {
    const a = gf16_encode_f32(-1.5);
    const b = gf16_encode_f32(-2.5);
    const result = gf16_add(a, b);
    const decoded = gf16_decode_to_f32(result);
    try std.testing.expectApproxEqAbs(-4.0, decoded, 0.1);
}
test "gf16_add_opposite_values" {
    const a = gf16_encode_f32(2.0);
    const b = gf16_encode_f32(-2.0);
    const result = gf16_add(a, b);
    try std.testing.expect(gf16_is_zero(result));
}
test "gf16_add_with_zero" {
    const a = gf16_encode_f32(3.5);
    const zero = gf16_encode_f32(0.0);
    const result1 = gf16_add(a, zero);
    const result2 = gf16_add(zero, a);
    const decoded1 = gf16_decode_to_f32(result1);
    const decoded2 = gf16_decode_to_f32(result2);
    try std.testing.expectApproxEqAbs(3.5, decoded1, 0.05);
    try std.testing.expectApproxEqAbs(3.5, decoded2, 0.05);
}
