test "gf16_trig_identity" {
    const x = gf16_encode_f32(0.5);
    const sin_val = gf16_decode_to_f32(gf16_sin(x));
    const cos_val = gf16_decode_to_f32(gf16_cos(x));
    const sum = (sin_val * sin_val) + (cos_val * cos_val);
    try std.testing.expectApproxEqAbs(1.0, sum, 0.1);
}
fn bench_gf16_encode_throughput() void {
    // bench: gf16_encode_throughput
    @setEvalBranchQuota(10000);
    var result: GF16 = 0;
    for (0 .. 1000) {
        result = gf16_encode_f32(1.5);
    }
    _ = result;
}
